const source = '---
title: Auth Flow
---
flowchart LR
  A[User] --> B[Login Page]
  B --> C{Valid Credentials?}
  C -->|No| B
  C -->|Yes| D{MFA Enabled?}
  D -->|Yes| E[Enter MFA Code]
  E --> F{Code Valid?}
  F -->|No| E
  D -->|No| G[Create Session]
  F -->|Yes| G
  G --> H[Dashboard]'
const parsed = mermaid.parseMermaid(source)
if (!parsed.ok) return { error: parsed.error }

const verify = mermaid.verifyMermaid(parsed.value)
const warnings = verify.warnings
if (!verify.ok) return { error: 'verify', warnings }

return { source }

